package com.hospital.management.dao.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.math.*;import java.sql.*;import java.time.*;import java.util.*;/** Prepared-statement Oracle persistence for bill headers. */public class BillDaoImpl implements BillDao{private final BillItemDao items;private final PaymentDao payments;private static final String S="SELECT b.*,p.PATIENT_NUMBER,p.FIRST_NAME||' '||p.LAST_NAME PATIENT_NAME,a.APPOINTMENT_DATE,a.DOCTOR_ID,d.FIRST_NAME||' '||d.LAST_NAME DOCTOR_NAME,dep.DEPARTMENT_ID,dep.DEPARTMENT_NAME FROM BILLS b JOIN PATIENTS p ON p.PATIENT_ID=b.PATIENT_ID LEFT JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=b.APPOINTMENT_ID LEFT JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID LEFT JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ";public BillDaoImpl(){this(new BillItemDaoImpl(),new PaymentDaoImpl());}public BillDaoImpl(BillItemDao i,PaymentDao p){items=i;payments=p;}public Optional<Bill>findById(Long id)throws SQLException{Optional<Bill>b=one(null,"b.BILL_ID",id,false);if(b.isPresent()){b.get().setItems(items.findByBillId(id));b.get().setPayments(payments.findByBillId(id));}return b;}public Optional<Bill>findByIdForUpdate(Connection c,Long id)throws SQLException{return one(c,"b.BILL_ID",id,true);}public Optional<Bill>findByBillNumber(String n)throws SQLException{return one(null,"b.BILL_NUMBER",n,false);}public Optional<Bill>findByAppointmentId(Long id)throws SQLException{return one(null,"b.APPOINTMENT_ID",id,false);}private Optional<Bill>one(Connection supplied,String f,Object v,boolean lock)throws SQLException{if(v==null)return Optional.empty();Connection c=supplied==null?DatabaseConnectionManager.getConnection():supplied;try(PreparedStatement s=c.prepareStatement(S+"WHERE "+f+"=?"+(lock?" FOR UPDATE OF b.STATUS,b.PAID_AMOUNT,b.BALANCE_AMOUNT":""))){s.setObject(1,v);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}finally{if(supplied==null)c.close();}}
public Page<Bill>findAll(PageRequest p,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+where()+" ORDER BY b.BILL_DATE DESC,b.BILL_ID DESC OFFSET ? ROWS FETCH NEXT ? ROWS ONLY")){int n=bind(s,p.getSearchTerm(),pi,di,dep,f,t,st);s.setInt(n++,p.getOffset());s.setInt(n,p.getPageSize());List<Bill>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return new Page<>(x,p.getPageNumber(),p.getPageSize(),count(p.getSearchTerm(),pi,di,dep,f,t,st));}}public long count(String q,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT COUNT(*) FROM BILLS b JOIN PATIENTS p ON p.PATIENT_ID=b.PATIENT_ID LEFT JOIN APPOINTMENTS a ON a.APPOINTMENT_ID=b.APPOINTMENT_ID LEFT JOIN DOCTORS d ON d.DOCTOR_ID=a.DOCTOR_ID LEFT JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID "+where())){bind(s,q,pi,di,dep,f,t,st);try(ResultSet r=s.executeQuery()){r.next();return r.getLong(1);}}}private String where(){return"WHERE (? IS NULL OR UPPER(b.BILL_NUMBER||' '||p.PATIENT_NUMBER||' '||p.FIRST_NAME||' '||p.LAST_NAME||' '||NVL(d.FIRST_NAME,'')||' '||NVL(d.LAST_NAME,'')||' '||NVL(dep.DEPARTMENT_NAME,'')||' '||b.STATUS) LIKE ? ESCAPE '\\') AND (? IS NULL OR b.PATIENT_ID=?) AND (? IS NULL OR a.DOCTOR_ID=?) AND (? IS NULL OR dep.DEPARTMENT_ID=?) AND (? IS NULL OR b.BILL_DATE>=?) AND (? IS NULL OR b.BILL_DATE<?) AND (? IS NULL OR b.STATUS=?) ";}private int bind(PreparedStatement s,String q,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st)throws SQLException{String x=q==null||q.isBlank()?null:"%"+q.trim().toUpperCase().replace("\\","\\\\").replace("%","\\%").replace("_","\\_")+"%";int i=1;s.setString(i++,x);s.setString(i++,x);i=pair(s,i,pi);i=pair(s,i,di);i=pair(s,i,dep);i=date(s,i,f);i=date(s,i,t==null?null:t.plusDays(1));String z=st==null||st.isBlank()?null:st.toUpperCase();s.setString(i++,z);s.setString(i++,z);return i;}private int pair(PreparedStatement s,int i,Long v)throws SQLException{if(v==null){s.setNull(i++,Types.NUMERIC);s.setNull(i++,Types.NUMERIC);}else{s.setLong(i++,v);s.setLong(i++,v);}return i;}private int date(PreparedStatement s,int i,LocalDate v)throws SQLException{if(v==null){s.setNull(i++,Types.DATE);s.setNull(i++,Types.DATE);}else{s.setDate(i++,java.sql.Date.valueOf(v));s.setDate(i++,java.sql.Date.valueOf(v));}return i;}
public long createBill(Connection c,Bill b)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO BILLS(BILL_NUMBER,PATIENT_ID,APPOINTMENT_ID,BILL_DATE,SUBTOTAL,TAX_AMOUNT,DISCOUNT_AMOUNT,TOTAL_AMOUNT,PAID_AMOUNT,BALANCE_AMOUNT,STATUS)VALUES(?,?,?,CURRENT_TIMESTAMP,?,?,?,?,?,?,?)",new String[]{"BILL_ID"})){s.setString(1,b.getBillNumber());s.setLong(2,b.getPatientId());if(b.getAppointmentId()==null)s.setNull(3,Types.NUMERIC);else s.setLong(3,b.getAppointmentId());s.setBigDecimal(4,b.getSubtotal());s.setBigDecimal(5,b.getTaxAmount());s.setBigDecimal(6,b.getDiscountAmount());s.setBigDecimal(7,b.getTotalAmount());s.setBigDecimal(8,b.getPaidAmount());s.setBigDecimal(9,b.getBalanceAmount());s.setString(10,b.getStatus());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){if(r.next())return r.getLong(1);throw new SQLException("No bill identifier returned");}}}public boolean updateBill(Connection c,Bill b)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE BILLS SET SUBTOTAL=?,TAX_AMOUNT=?,DISCOUNT_AMOUNT=?,TOTAL_AMOUNT=?,BALANCE_AMOUNT=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE BILL_ID=? AND STATUS='UNPAID'")){s.setBigDecimal(1,b.getSubtotal());s.setBigDecimal(2,b.getTaxAmount());s.setBigDecimal(3,b.getDiscountAmount());s.setBigDecimal(4,b.getTotalAmount());s.setBigDecimal(5,b.getBalanceAmount());s.setLong(6,b.getBillId());return s.executeUpdate()==1;}}public boolean updateFinancialSummary(Connection c,Long id,BigDecimal sub,BigDecimal tax,BigDecimal discount,BigDecimal total,BigDecimal paid,BigDecimal balance,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE BILLS SET SUBTOTAL=?,TAX_AMOUNT=?,DISCOUNT_AMOUNT=?,TOTAL_AMOUNT=?,PAID_AMOUNT=?,BALANCE_AMOUNT=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE BILL_ID=?")){s.setBigDecimal(1,sub);s.setBigDecimal(2,tax);s.setBigDecimal(3,discount);s.setBigDecimal(4,total);s.setBigDecimal(5,paid);s.setBigDecimal(6,balance);s.setString(7,st);s.setLong(8,id);return s.executeUpdate()==1;}}public boolean updateStatus(Connection c,Long id,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE BILLS SET STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE BILL_ID=?")){s.setString(1,st);s.setLong(2,id);return s.executeUpdate()==1;}}public boolean existsActiveBillByAppointment(Long id)throws SQLException{return exists(id,null);}public boolean existsActiveBillByAppointmentExcludingBill(Long a,Long b)throws SQLException{return exists(a,b);}private boolean exists(Long a,Long b)throws SQLException{if(a==null)return false;try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT 1 FROM BILLS WHERE APPOINTMENT_ID=? AND STATUS<>'CANCELLED'"+(b==null?"":" AND BILL_ID<>?")+" FETCH FIRST 1 ROW ONLY")){s.setLong(1,a);if(b!=null)s.setLong(2,b);try(ResultSet r=s.executeQuery()){return r.next();}}}private Bill map(ResultSet r)throws SQLException{Bill b=new Bill();b.setBillId(r.getLong("BILL_ID"));b.setBillNumber(r.getString("BILL_NUMBER"));b.setPatientId(r.getLong("PATIENT_ID"));b.setPatientNumber(r.getString("PATIENT_NUMBER"));b.setPatientName(r.getString("PATIENT_NAME"));long a=r.getLong("APPOINTMENT_ID"),d=r.getLong("DOCTOR_ID");b.setAppointmentId(r.wasNull()?null:a);b.setDoctorId(d==0?null:d);b.setDoctorName(r.getString("DOCTOR_NAME"));b.setDepartmentName(r.getString("DEPARTMENT_NAME"));Timestamp bd=r.getTimestamp("BILL_DATE"),ad=r.getTimestamp("APPOINTMENT_DATE"),c=r.getTimestamp("CREATED_AT"),u=r.getTimestamp("UPDATED_AT");b.setBillDate(bd==null?null:bd.toLocalDateTime().toLocalDate());b.setAppointmentDate(ad==null?null:ad.toLocalDateTime().toLocalDate());b.setSubtotal(r.getBigDecimal("SUBTOTAL"));b.setTaxAmount(r.getBigDecimal("TAX_AMOUNT"));b.setDiscountAmount(r.getBigDecimal("DISCOUNT_AMOUNT"));b.setTotalAmount(r.getBigDecimal("TOTAL_AMOUNT"));b.setPaidAmount(r.getBigDecimal("PAID_AMOUNT"));b.setBalanceAmount(r.getBigDecimal("BALANCE_AMOUNT"));b.setStatus(r.getString("STATUS"));b.setCreatedAt(c==null?null:c.toLocalDateTime());b.setUpdatedAt(u==null?null:u.toLocalDateTime());return b;}}
